@register.simple_tag
def icon(name, size=24, css_class="", stroke_width=2):
    inner = ICONS.get(name, ICONS["triangle-alert"])
    cls = "icon " + css_class if css_class else "icon"
    return mark_safe(
        '<svg class="{cls}" width="{size}" height="{size}" viewBox="0 0 24 24" '
        'fill="none" stroke="currentColor" stroke-width="{sw}" '
        'stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">{inner}</svg>'.format(
            cls=cls, size=size, sw=stroke_width, inner=inner
        )
    )
